import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,f as n}from"./app-7cfa41e7.js";const l={},s=n(`<h1 id="java基础知识" tabindex="-1"><a class="header-anchor" href="#java基础知识" aria-hidden="true">#</a> Java基础知识</h1><h3 id="封装" tabindex="-1"><a class="header-anchor" href="#封装" aria-hidden="true">#</a> 封装:</h3><p>利用抽象数据类型将数据和基于数据的操作封装在一起，使其构成一个不可分割的独立实体，数据被保护在抽象数据类型内部，尽可能隐藏内部细节，只保留一些对外使用的接口与外部保持联系。用户不需要知道内部实现。</p><p>优点:</p><ul><li>减少耦合: 可以独立地开发、测试、优化、使用、理解和修改</li><li>减轻维护的负担: 可以更容易被程序员理解，并且在调试的时候可以不影响其他模块</li><li>有效地调节性能: 可以通过剖析确定哪些模块影响了系统的性能</li><li>提高软件的可重用性</li><li>降低了构建大型系统的风险: 即使整个系统不可用，但是这些独立的模块却有可能是可用的</li></ul><h3 id="继承" tabindex="-1"><a class="header-anchor" href="#继承" aria-hidden="true">#</a> 继承：</h3><h3 id="多态" tabindex="-1"><a class="header-anchor" href="#多态" aria-hidden="true">#</a> 多态：</h3><p>多态分为编译时多态和运行时多态:</p><ul><li>编译时多态主要指方法的重载</li><li>运行时多态指程序中定义的对象引用所指向的具体类型在运行期间才确定</li></ul><p>运行时多态有三个条件:</p><ul><li>继承</li><li>覆盖(重写)</li><li>向上转型</li></ul><p>下面的代码中，乐器类(Instrument)有两个子类: Wind 和 Percussion，它们都覆盖了父类的 play() 方法，并且在 main() 方法中使用父类 Instrument 来引用 Wind 和 Percussion 对象。在 Instrument 引用调用 play() 方法时，会执行实际引用对象所在类的 play() 方法，而不是 Instrument 类的方法。</p><div class="language-Java line-numbers-mode" data-ext="Java"><pre class="language-Java"><code>public class Instrument {public void play() {System.out.println(&quot;Instrument is playing...&quot;);}}public class Wind extends Instrument {public void play() {System.out.println(&quot;Wind is playing...&quot;);}}public class Percussion extends Instrument {public void play() {System.out.println(&quot;Percussion is playing...&quot;);}}public class Music {public static void main(String[] args) {List&lt;Instrument&gt; instruments = new ArrayList&lt;&gt;();
        instruments.add(new Wind());
        instruments.add(new Percussion());for(Instrument instrument : instruments) {
            instrument.play();}}}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="基本类型" tabindex="-1"><a class="header-anchor" href="#基本类型" aria-hidden="true">#</a> 基本类型：</h3><p>基本类型都有对应的包装类型，基本类型与其对应的包装类型之间的赋值使用自动装箱与拆箱完成。</p><div class="language-Java line-numbers-mode" data-ext="Java"><pre class="language-Java"><code>Integer x = 2;     // 装箱    
 int y = x;         // 拆箱   
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="缓存池" tabindex="-1"><a class="header-anchor" href="#缓存池" aria-hidden="true">#</a> 缓存池：</h3><ul><li>new Integer(123) 每次都会新建一个对象</li><li>Integer.valueOf(123) 会使用缓存池中的对象，多次调用会取得同一个对象的引用。</li></ul><p>比如说Integer就自带缓存池</p><p>如果装箱的过程中</p><div class="language-Java line-numbers-mode" data-ext="Java"><pre class="language-Java"><code>Integer x=123;//会自动调用缓存池中的对象
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在 Java 8 中，Integer 缓存池的大小默认为 -128~127。如果超出了这个范围会去在堆中new Integer对象</p><p>基本类型对应的缓冲池如下:</p><ul><li>boolean values true and false</li><li>all byte values</li><li>short values between -128 and 127</li><li>int values between -128 and 127</li><li>char in the range \\u0000 to \\u007F</li></ul><p>在使用这些基本类型对应的包装类型时，就可以直接使用缓冲池中的对象。</p>`,25),t=[s];function r(d,u){return a(),i("div",null,t)}const p=e(l,[["render",r],["__file","1.html.vue"]]);export{p as default};
